SELECT count(*) AS totalOrder FROM tb_order
WHERE retailer_account_id = #{currentUserId}
  AND (EXTRACT(YEAR FROM created_date) = #{year} AND EXTRACT(MONTH FROM created_date) = #{month})

SELECT count(*) FROM tb_order
WHERE retailer_account_id = #{currentUserId}
  AND status_id = #{statusId}
  AND (EXTRACT(YEAR FROM created_date) = #{year} AND EXTRACT(MONTH FROM created_date) = #{month})

SELECT sum(qty) AS totalQuantityOrder
FROM tb_order_detail TOD
         INNER JOIN tb_order T ON T.id = TOD.order_id
WHERE retailer_account_id = #{currentUserId}
  AND status_id = #{statusId}
  AND (EXTRACT(YEAR FROM created_date) = #{year} AND EXTRACT(MONTH FROM created_date) = #{month})

SELECT DISTINCT store_id FROM tb_order
WHERE retailer_account_id = #{currentUserId}
  AND status_id = #{statusId}
  AND (EXTRACT(YEAR FROM created_date) = #{year} AND EXTRACT(MONTH FROM created_date) = #{month})

SELECT count(*) FROM tb_rating_detail
WHERE retailer_account_id = #{currentUserId}
  AND (EXTRACT(YEAR FROM created_date) = #{year} AND EXTRACT(MONTH FROM created_date) = #{month})

